define('tiny_imageia/options', ['editor_tiny/options'], function(TinyOptions) {
  const pluginName = 'tiny_imageia/plugin';
  const apiKeyOptionName = TinyOptions.getPluginOptionName(pluginName, 'apikey');
  const register = (editor) => editor.options.register(apiKeyOptionName, {processor: 'string'});
  const getApiKey = (editor) => editor.options.get(apiKeyOptionName) || '';
  return {register, getApiKey};
});
